/**
 * bundle_data.js
 *
 * Merges all 36 state JSON files into a single data.js file that exposes
 * a global `window.INDIA_HERITAGE_DATA` object. This eliminates 36 separate
 * HTTP fetch requests on page load, down to just 1 script include.
 *
 * Usage:
 *   node bundle_data.js
 *
 * Output:
 *   js/data.js   ← include this in index.html BEFORE app.js
 */

const fs   = require('fs');
const path = require('path');

const DATA_DIR    = path.join(__dirname, 'datasets', 'data');
const OUTPUT_FILE = path.join(__dirname, 'js', 'data.js');

const files = fs.readdirSync(DATA_DIR).filter(f => f.endsWith('.json'));

const merged = {};
let count = 0;

files.forEach(file => {
    const raw = fs.readFileSync(path.join(DATA_DIR, file), 'utf-8').trim();
    if (!raw || raw === '{}') return;
    try {
        const parsed = JSON.parse(raw);
        const states = parsed.states || {};
        Object.assign(merged, states);
        count++;
    } catch (e) {
        console.error(`⚠  Could not parse ${file}: ${e.message}`);
    }
});

const output = `// Auto-generated by bundle_data.js — DO NOT EDIT MANUALLY
// Run: node bundle_data.js to regenerate after updating any JSON file
window.INDIA_HERITAGE_DATA = ${JSON.stringify(merged, null, 2)};
`;

fs.writeFileSync(OUTPUT_FILE, output, 'utf-8');

console.log(`\n✅  Bundled ${count} state files → js/data.js`);
console.log(`   States included: ${Object.keys(merged).join(', ')}`);
console.log(`   File size: ${(Buffer.byteLength(output) / 1024).toFixed(1)} KB\n`);
console.log(`Next steps:`);
console.log(`  1. Add to index.html BEFORE app.js:`);
console.log(`     <script src="js/data.js"></script>`);
console.log(`  2. app.js will automatically use window.INDIA_HERITAGE_DATA`);
console.log(`     (no changes needed to app.js — it checks for this global)\n`);
